{"code":"import json, pandas as pd, re

qli = pd.DataFrame(var_call_ncd8Ik51jmmX6cecfNTfkXL4)
pbe = pd.DataFrame(var_call_qIgIGfFvxYATcn46ZMuK5RvE)

# normalize ids
for df, col in [(qli,'PricebookEntryId'),(qli,'Product2Id'),(pbe,'PricebookEntryId'),(pbe,'Product2Id')]:
    df[col+'_norm'] = df[col].astype(str).str.replace('#','', regex=False).str.strip()

# numeric conversions
for c in ['Quantity','UnitPrice','Discount','TotalPrice']:
    qli[c] = pd.to_numeric(qli[c], errors='coerce')

pbe['CatalogUnitPrice'] = pd.to_numeric(pbe['CatalogUnitPrice'], errors='coerce')

m = qli.merge(pbe, on='PricebookEntryId_norm', how='left', suffixes=('','_pbe'))

issues = set()
for _, r in m.iterrows():
    if pd.notna(r.get('CatalogUnitPrice')) and pd.notna(r.get('UnitPrice')):
        if abs(float(r['UnitPrice']) - float(r['CatalogUnitPrice'])) > 0.01:
            issues.add('PRICE_MISMATCH')
    if pd.notna(r.get('Discount')) and float(r['Discount']) > 10:
        issues.add('DISCOUNT_GT_10')

# load knowledge articles
path = var_call_DlQ5jERcoi4eacqPcBZdp65s
with open(path,'r',encoding='utf-8') as f:
    kav = json.load(f)

kdf = pd.DataFrame(kav)
for col in ['title','summary','faq_answer__c']:
    if col in kdf.columns:
        kdf[col] = kdf[col].fillna('').astype(str)
    else:
        kdf[col] = ''

keywords = []
if 'DISCOUNT_GT_10' in issues:
    keywords += ['discount', 'maximum discount', 'max discount', 'approval', '10%']
if 'PRICE_MISMATCH' in issues:
    keywords += ['unit price', 'pricebook', 'standard price', 'pricing', 'catalog price']

text = (kdf['title'] + ' ' + kdf['summary'] + ' ' + kdf['faq_answer__c']).str.lower()
score = pd.Series(0, index=kdf.index, dtype='int64')
for kw in keywords:
    patt = re.escape(kw.lower())
    score = score + text.str.count(patt)

best_id = None
if len(score) > 0:
    best_idx = int(score.idxmax())
    if score.loc[best_idx] > 0:
        best_id = kdf.loc[best_idx, 'id']

print('__RESULT__:')
print(json.dumps(best_id))"}
